import { useState, useEffect, useRef } from "react";
import { sendChatMessage, downloadReportPDF } from "../services/api";
import "./ChatBox.css";

function ChatBox({ onFinalReport }) {
  const userId = localStorage.getItem("user_id");

  const [message, setMessage] = useState("");
  const [chat, setChat] = useState([
    { sender: "Doctor-AI", text: "Hello 🙂 I’m glad you reached out. What’s your name?" }
  ]);
  const [loading, setLoading] = useState(false);

  // ✅ NEW: store final report
  const [finalReport, setFinalReport] = useState(null);

  const chatEndRef = useRef(null);

  // Auto-scroll
  useEffect(() => {
    chatEndRef.current?.scrollIntoView({ behavior: "smooth" });
  }, [chat, loading]);

  const sendMessage = async () => {
    if (!message.trim()) return;

    const userMsg = message.trim();
    setMessage("");

    setChat(prev => [...prev, { sender: "You", text: userMsg }]);
    setLoading(true);

    try {
      const res = await sendChatMessage({
        user_id: userId,
        message: userMsg
      });

      const replyText =
        typeof res.data.reply === "string"
          ? res.data.reply
          : String(res.data.reply);

      setChat(prev => [...prev, { sender: "Doctor-AI", text: replyText }]);

      // ✅ FINAL REPORT DETECTION (your logic + improved)
      if (
        replyText.includes("FINAL ASSESSMENT") ||
        replyText.includes("SUMMARY REPORT")
      ) {
        setFinalReport(replyText);
        onFinalReport && onFinalReport(replyText);
      }

    } catch (err) {
      setChat(prev => [
        ...prev,
        { sender: "Doctor-AI", text: "Sorry 😔 I couldn’t process that. Please try again." }
      ]);
    }

    setLoading(false);
  };

  // ✅ NEW: Download PDF
  const downloadPDF = async () => {
    try {
      const res = await downloadReportPDF({
        user_id: userId,
        report: finalReport
      });

      const blob = new Blob([res.data], { type: "application/pdf" });
      const url = window.URL.createObjectURL(blob);

      const a = document.createElement("a");
      a.href = url;
      a.download = "Medical_Report.pdf";
      a.click();
    } catch {
      alert("Failed to download report");
    }
  };

  return (
    <div className="chatbox-container">
      <div className="chat-messages">
        {chat.map((c, i) => (
          <div
            key={i}
            className={c.sender === "You" ? "chat-bubble user" : "chat-bubble doctor"}
          >
            <span className="sender">{c.sender}</span>
            <p>{c.text}</p>
          </div>
        ))}

        {loading && (
          <div className="chat-bubble doctor typing">
            Doctor-AI is typing…
          </div>
        )}

        <div ref={chatEndRef} />
      </div>

      <div className="chat-input">
        <input
          value={message}
          onChange={e => setMessage(e.target.value)}
          placeholder="Type your message…"
          onKeyDown={e => e.key === "Enter" && sendMessage()}
        />
        <button onClick={sendMessage}>Send ➤</button>
      </div>

      {/* ✅ NEW: Download button appears ONLY after final report */}
      {finalReport && (
        <button className="download-btn" onClick={downloadPDF}>
          ⬇️ Download Medical Report (PDF)
        </button>
      )}
    </div>
  );
}

export default ChatBox;
